"use client"

import * as React from "react"
import { cn } from "@/lib/utils"
import type { IconSvgElement } from "@hugeicons/react"

/* ── Types ── */

export interface ComposerTask {
  label: string
  done: boolean
  dimmed?: boolean
}

export interface ComposerFile {
  name: string
  size: string
  type: "file" | "image"
}

export interface ComposerScopeItem {
  id: string
  label: string
  icon: IconSvgElement
}

/* ── Context ── */

interface ComposerContextValue {
  value: string
  onValueChange: (value: string) => void
  isFocused: boolean
  setIsFocused: (focused: boolean) => void
  isSending: boolean
  send: () => void
  disabled: boolean
  textareaRef: React.RefObject<HTMLTextAreaElement | null>
}

const ComposerContext = React.createContext<ComposerContextValue | null>(null)

export function useComposer(): ComposerContextValue {
  const ctx = React.useContext(ComposerContext)
  if (!ctx) {
    throw new Error("useComposer must be used within a <Composer />")
  }
  return ctx
}

/* ── Composer (root) ── */

export function Composer({
  value: valueProp,
  defaultValue = "",
  onValueChange: onValueChangeProp,
  onSend,
  disabled = false,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  value?: string
  defaultValue?: string
  onValueChange?: (value: string) => void
  onSend?: (value: string) => void
  disabled?: boolean
}) {
  const [_value, _setValue] = React.useState(defaultValue)
  const value = valueProp ?? _value
  const onValueChange = React.useCallback(
    (v: string) => {
      if (onValueChangeProp) onValueChangeProp(v)
      else _setValue(v)
    },
    [onValueChangeProp],
  )

  const [isFocused, setIsFocused] = React.useState(false)
  const [isSending, setIsSending] = React.useState(false)
  const textareaRef = React.useRef<HTMLTextAreaElement | null>(null)

  const send = React.useCallback(() => {
    if (disabled) return
    if (!value.trim()) return
    setIsSending(true)
    const currentValue = value
    setTimeout(() => {
      onValueChange("")
      setIsSending(false)
      if (textareaRef.current) textareaRef.current.style.height = "auto"
    }, 400)
    onSend?.(currentValue)
  }, [value, disabled, onValueChange, onSend])

  const ctx = React.useMemo<ComposerContextValue>(
    () => ({
      value,
      onValueChange,
      isFocused,
      setIsFocused,
      isSending,
      send,
      disabled,
      textareaRef,
    }),
    [value, onValueChange, isFocused, isSending, send, disabled],
  )

  return (
    <ComposerContext.Provider value={ctx}>
      <div
        data-slot="composer"
        className={cn(
          "mx-auto flex w-full max-w-[720px] flex-col items-center",
          className,
        )}
        {...props}
      >
        {children}
      </div>
    </ComposerContext.Provider>
  )
}

/* ── ComposerIslands ── */

export function ComposerIslands({
  className,
  children,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="composer-islands"
      className={cn("flex w-full flex-col items-center", className)}
      {...props}
    >
      {children}
    </div>
  )
}

/* ── ComposerCard ── */

export function ComposerCard({
  className,
  children,
  ...props
}: React.ComponentProps<"div">) {
  const { isFocused } = useComposer()

  return (
    <div
      data-slot="composer-card"
      className={cn(
        "relative z-1 w-full rounded-xl border bg-background transition-shadow duration-300 ease-out",
        isFocused
          ? "border-foreground/15 shadow-[0_0_0_1px_rgba(0,0,0,0.03),0_2px_12px_rgba(0,0,0,0.06),0_8px_32px_rgba(0,0,0,0.04)]"
          : "border-border shadow-[0_1px_3px_rgba(0,0,0,0.04),0_4px_16px_rgba(0,0,0,0.03)]",
        className,
      )}
      {...props}
    >
      {children}
    </div>
  )
}

/* ── Re-exports ── */

export { ComposerInput } from "./composer-input"
export {
  ComposerToolbar,
  ComposerMenu,
  ComposerContextRing,
  ComposerSend,
} from "./composer-toolbar"
export {
  ComposerScope,
  ComposerReply,
  ComposerPlan,
} from "./composer-islands"
export { ComposerAttachments } from "./composer-attachments"
export { ComposerSuggestions } from "./composer-suggestions"

"use client"

import * as React from "react"
import { cn } from "@/lib/utils"
import { useComposer } from "./composer"

export function ComposerInput({
  placeholder = "Type a message...",
  maxHeight = 160,
  className,
  ...props
}: Omit<React.ComponentProps<"textarea">, "value" | "onChange"> & {
  maxHeight?: number
}) {
  const { value, onValueChange, setIsFocused, send, textareaRef } =
    useComposer()

  React.useEffect(() => {
    const ta = textareaRef.current
    if (!ta) return
    ta.style.height = "auto"
    ta.style.height = Math.min(ta.scrollHeight, maxHeight) + "px"
  }, [value, maxHeight, textareaRef])

  return (
    <div
      data-slot="composer-input"
      className={cn("px-4 pt-3 pb-1", className)}
    >
      <textarea
        ref={textareaRef}
        value={value}
        onChange={(e) => onValueChange(e.target.value)}
        onFocus={() => setIsFocused(true)}
        onBlur={() => setIsFocused(false)}
        onKeyDown={(e) => {
          if (e.key === "Enter" && !e.shiftKey) {
            e.preventDefault()
            send()
          }
        }}
        placeholder={placeholder}
        rows={1}
        className="max-h-[160px] min-h-[32px] w-full resize-none bg-transparent text-sm leading-relaxed placeholder:text-muted-foreground/50 focus:outline-none"
        style={{ maxHeight }}
        {...props}
      />
    </div>
  )
}

"use client"

import * as React from "react"
import { cn } from "@/lib/utils"
import { HugeiconsIcon } from "@hugeicons/react"
import { ArrowUp02Icon, Add01Icon } from "@hugeicons/core-free-icons"
import {
  DropdownMenu,
  DropdownMenuTrigger,
  DropdownMenuContent,
} from "@/components/ui/dropdown-menu"
import { useComposer } from "./composer"

/* ── ComposerToolbar ── */

export function ComposerToolbar({
  className,
  children,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="composer-toolbar"
      className={cn("flex items-center gap-1 px-3 pt-0.5 pb-3", className)}
      {...props}
    >
      {children}
    </div>
  )
}

/* ── ComposerMenu ── */

export function ComposerMenu({
  className,
  children,
}: {
  children: React.ReactNode
  className?: string
}) {
  return (
    <DropdownMenu>
      <DropdownMenuTrigger
        className={cn(
          "flex h-7 w-7 items-center justify-center rounded-md text-muted-foreground/50 transition-all duration-200 outline-none hover:bg-muted/60 hover:text-foreground",
          className,
        )}
      >
        <HugeiconsIcon icon={Add01Icon} size={16} strokeWidth={1.5} />
      </DropdownMenuTrigger>
      <DropdownMenuContent
        side="top"
        sideOffset={8}
        align="start"
        className="min-w-[200px]"
      >
        {children}
      </DropdownMenuContent>
    </DropdownMenu>
  )
}

/* ── ComposerContextRing ── */

export function ComposerContextRing({
  used,
  total,
  label,
  className,
  ...props
}: React.ComponentProps<"div"> & {
  used: number
  total: number
  label?: string
}) {
  const [hover, setHover] = React.useState(false)
  const pct = total > 0 ? used / total : 0
  const r = 6
  const circ = 2 * Math.PI * r
  const offset = circ * (1 - pct)
  const displayLabel = label ?? `${used}k / ${total}k tokens`
  const pctLabel = `${Math.round(pct * 100)}%`

  return (
    <div
      data-slot="composer-context-ring"
      className={cn("relative mr-1 flex items-center gap-1.5", className)}
      onMouseEnter={() => setHover(true)}
      onMouseLeave={() => setHover(false)}
      {...props}
    >
      <svg width="16" height="16" viewBox="0 0 16 16" className="opacity-50">
        <circle
          cx="8"
          cy="8"
          r={r}
          fill="none"
          stroke="currentColor"
          strokeWidth="1.5"
          opacity="0.15"
        />
        <circle
          cx="8"
          cy="8"
          r={r}
          fill="none"
          stroke="currentColor"
          strokeWidth="1.5"
          strokeDasharray={circ}
          strokeDashoffset={offset}
          strokeLinecap="round"
          transform="rotate(-90 8 8)"
          className="text-muted-foreground"
        />
      </svg>
      {hover && (
        <div className="absolute bottom-full left-1/2 z-10 mb-2 -translate-x-1/2 whitespace-nowrap rounded-md bg-foreground px-2.5 py-1.5 text-xs text-background shadow-sm">
          <span>{displayLabel} ({pctLabel})</span>
          <div className="absolute left-1/2 top-full -translate-x-1/2 border-4 border-transparent border-t-foreground" />
        </div>
      )}
    </div>
  )
}

/* ── ComposerSend ── */

export function ComposerSend({
  className,
  ...props
}: React.ComponentProps<"button">) {
  const { value, isSending, send } = useComposer()
  const [arrowAnim, setArrowAnim] = React.useState(false)
  const hasContent = value.trim().length > 0

  const handleClick = React.useCallback(() => {
    setArrowAnim(true)
    send()
    setTimeout(() => setArrowAnim(false), 500)
  }, [send])

  return (
    <button
      data-slot="composer-send"
      type="button"
      onClick={handleClick}
      disabled={!hasContent}
      className={cn(
        "flex h-7 w-7 items-center justify-center rounded-full transition-all duration-200",
        hasContent
          ? "bg-foreground text-background hover:opacity-90"
          : "cursor-not-allowed bg-muted/60 text-muted-foreground/40",
        isSending ? "animate-composer-send" : "",
        className,
      )}
      {...props}
    >
      <span className={arrowAnim ? "animate-composer-arrow" : ""}>
        <HugeiconsIcon icon={ArrowUp02Icon} size={15} strokeWidth={2} />
      </span>
    </button>
  )
}

"use client"

import * as React from "react"
import { cn } from "@/lib/utils"
import { HugeiconsIcon } from "@hugeicons/react"
import {
  Cancel01Icon,
  MailReply01Icon,
  Task01Icon,
  ArrowExpand01Icon,
  ArrowShrink01Icon,
} from "@hugeicons/core-free-icons"
import type { ComposerScopeItem } from "./composer"
import type { ComposerTask } from "./composer"

/* ── Island wrapper (used by each island primitive) ── */

function Island({
  className,
  children,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      className={cn("animate-composer-island w-[95%]", className)}
      style={{ zIndex: 0 }}
      {...props}
    >
      <div
        data-slot="composer-island"
        className="border border-b-0 border-border bg-background first:rounded-t-xl first:shadow-[0_-1px_6px_rgba(0,0,0,0.04),0_-4px_16px_rgba(0,0,0,0.03)]"
      >
        {children}
      </div>
    </div>
  )
}

/* ── ComposerScope ── */

export function ComposerScope({
  items,
  onRemove,
  onDismiss,
  className,
  ...props
}: React.ComponentProps<"div"> & {
  items: ComposerScopeItem[]
  onRemove?: (id: string) => void
  onDismiss?: () => void
}) {
  return (
    <Island className={className} {...props}>
      <div className="flex items-center gap-2 px-3 py-2.5">
        <div className="flex min-w-0 flex-1 flex-wrap items-center gap-1.5">
          {items.map((item) => (
            <span
              key={item.id}
              className="animate-composer-slide group/scope inline-flex items-center gap-1.5 rounded-md border border-border bg-muted/40 px-2 py-0.5 text-xs text-foreground"
            >
              <HugeiconsIcon
                icon={item.icon}
                size={12}
                strokeWidth={1.5}
                className="shrink-0 text-muted-foreground"
              />
              <span className="max-w-[160px] truncate">{item.label}</span>
              {onRemove && (
                <button
                  type="button"
                  onClick={() => onRemove(item.id)}
                  className="text-muted-foreground/40 opacity-0 transition-colors group-hover/scope:opacity-100 hover:text-foreground"
                >
                  <HugeiconsIcon
                    icon={Cancel01Icon}
                    size={10}
                    strokeWidth={2}
                  />
                </button>
              )}
            </span>
          ))}
        </div>
        {onDismiss && (
          <button
            type="button"
            onClick={onDismiss}
            className="shrink-0 text-muted-foreground/40 transition-colors hover:text-foreground"
          >
            <HugeiconsIcon icon={Cancel01Icon} size={14} strokeWidth={1.5} />
          </button>
        )}
      </div>
    </Island>
  )
}

/* ── ComposerReply ── */

export function ComposerReply({
  onDismiss,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  onDismiss?: () => void
}) {
  return (
    <Island className={className} {...props}>
      <div className="flex items-center gap-2 px-4 py-2.5">
        <HugeiconsIcon
          icon={MailReply01Icon}
          size={13}
          strokeWidth={1.5}
          className="shrink-0 text-muted-foreground/60"
        />
        <span className="flex-1 truncate text-xs text-muted-foreground">
          {children}
        </span>
        {onDismiss && (
          <button
            type="button"
            onClick={onDismiss}
            className="shrink-0 text-muted-foreground/60 transition-colors hover:text-foreground"
          >
            <HugeiconsIcon icon={Cancel01Icon} size={14} strokeWidth={1.5} />
          </button>
        )}
      </div>
    </Island>
  )
}

/* ── ComposerPlan ── */

export function ComposerPlan({
  tasks,
  defaultExpanded = false,
  className,
  ...props
}: React.ComponentProps<"div"> & {
  tasks: ComposerTask[]
  defaultExpanded?: boolean
}) {
  const [expanded, setExpanded] = React.useState(defaultExpanded)
  const completedCount = tasks.filter((t) => t.done).length

  return (
    <Island className={className} {...props}>
      <div className="px-4 py-3">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2 text-xs text-muted-foreground">
            <HugeiconsIcon icon={Task01Icon} size={13} strokeWidth={1.5} />
            <span>
              {completedCount} out of {tasks.length} tasks completed
            </span>
          </div>
          <button
            type="button"
            onClick={() => setExpanded(!expanded)}
            className="text-muted-foreground/60 transition-colors hover:text-foreground"
          >
            <HugeiconsIcon
              icon={expanded ? ArrowShrink01Icon : ArrowExpand01Icon}
              size={14}
              strokeWidth={1.5}
            />
          </button>
        </div>

        {expanded && (
          <div className="animate-composer-slide mt-3 space-y-2.5">
            {tasks.map((task, i) => (
              <div
                key={i}
                className={cn(
                  "flex items-start gap-2.5 text-sm leading-snug",
                  task.dimmed
                    ? "text-muted-foreground/40"
                    : "text-foreground",
                )}
              >
                <span
                  className={cn(
                    "mt-[3px] flex h-[14px] w-[14px] shrink-0 items-center justify-center rounded-full border",
                    task.dimmed
                      ? "border-muted-foreground/20"
                      : "border-muted-foreground/40",
                  )}
                />
                <span>
                  {i + 1}. {task.label}
                </span>
              </div>
            ))}
          </div>
        )}
      </div>
    </Island>
  )
}

"use client"

import * as React from "react"
import { cn } from "@/lib/utils"
import { HugeiconsIcon } from "@hugeicons/react"
import { Cancel01Icon, File01Icon, Image01Icon } from "@hugeicons/core-free-icons"
import type { ComposerFile } from "./composer"

const FILE_ICONS = {
  file: File01Icon,
  image: Image01Icon,
} as const

export function ComposerAttachments({
  files,
  onRemove,
  className,
  ...props
}: React.ComponentProps<"div"> & {
  files: ComposerFile[]
  onRemove?: (name: string) => void
}) {
  if (files.length === 0) return null

  return (
    <div
      data-slot="composer-attachments"
      className={cn("animate-composer-slide flex gap-2 px-4 pt-3 pb-1", className)}
      {...props}
    >
      {files.map((file) => (
        <div
          key={file.name}
          className="group flex items-center gap-2 rounded-lg border border-border/60 bg-muted/40 px-3 py-2"
        >
          <HugeiconsIcon
            icon={FILE_ICONS[file.type]}
            size={14}
            strokeWidth={1.5}
            className="shrink-0 text-muted-foreground"
          />
          <div className="min-w-0">
            <p className="max-w-[140px] truncate text-xs font-medium">
              {file.name}
            </p>
            <p className="text-[10px] text-muted-foreground">{file.size}</p>
          </div>
          {onRemove && (
            <button
              type="button"
              onClick={() => onRemove(file.name)}
              className="ml-0.5 text-muted-foreground/40 opacity-0 transition-colors group-hover:opacity-100 hover:text-foreground"
            >
              <HugeiconsIcon icon={Cancel01Icon} size={12} strokeWidth={1.5} />
            </button>
          )}
        </div>
      ))}
    </div>
  )
}

"use client"

import * as React from "react"
import { cn } from "@/lib/utils"
import { useComposer } from "./composer"

export function ComposerSuggestions({
  items,
  onSelect,
  className,
  ...props
}: React.ComponentProps<"div"> & {
  items: string[]
  onSelect?: (suggestion: string) => void
}) {
  const { onValueChange, textareaRef } = useComposer()
  const [flashChip, setFlashChip] = React.useState<string | null>(null)

  const handleClick = React.useCallback(
    (suggestion: string) => {
      setFlashChip(suggestion)
      setTimeout(() => {
        onValueChange(suggestion)
        setFlashChip(null)
        textareaRef.current?.focus()
        onSelect?.(suggestion)
      }, 250)
    },
    [onValueChange, textareaRef, onSelect],
  )

  if (items.length === 0) return null

  return (
    <div
      data-slot="composer-suggestions"
      className={cn(
        "animate-composer-slide mt-3 flex flex-wrap justify-center gap-1.5",
        className,
      )}
      {...props}
    >
      {items.map((s) => (
        <button
          key={s}
          type="button"
          onClick={() => handleClick(s)}
          className={cn(
            "rounded-md border border-border/60 px-2.5 py-1 text-xs text-muted-foreground transition-all duration-200 hover:border-border hover:bg-muted/40 hover:text-foreground",
            flashChip === s ? "animate-composer-chip" : "",
          )}
        >
          {s}
        </button>
      ))}
    </div>
  )
}
